import argparse
import json
import sys
import time
import uuid
from typing import Optional

import pika


QUEUE_NAME = "task_queue"


def create_connection():
    parameters = pika.ConnectionParameters(host="localhost", port=5672)
    return pika.BlockingConnection(parameters)


def declare_queue(channel, queue_name: str):
    channel.queue_declare(queue=queue_name, durable=True)


def publish_task(message: str, queue_name: str = QUEUE_NAME):
    connection = create_connection()
    try:
        channel = connection.channel()
        declare_queue(channel, queue_name)
        channel.basic_publish(
            exchange="",
            routing_key=queue_name,
            body=message.encode("utf-8"),
            properties=pika.BasicProperties(
                delivery_mode=2,
                content_type="application/json" if _looks_like_json(message) else "text/plain",
                message_id=str(uuid.uuid4()),
                timestamp=int(time.time()),
            ),
        )
        print(f"Published task to '{queue_name}': {message}")
    finally:
        connection.close()


def _looks_like_json(value: str) -> bool:
    try:
        json.loads(value)
        return True
    except Exception:
        return False


def process_task(body: bytes):
    payload = body.decode("utf-8")
    print(f"Processing task: {payload}")
    time.sleep(1)
    print(f"Completed task: {payload}")


def start_consumer(queue_name: str = QUEUE_NAME, prefetch_count: int = 1):
    connection = create_connection()
    channel = connection.channel()
    declare_queue(channel, queue_name)
    channel.basic_qos(prefetch_count=prefetch_count)

    def callback(ch, method, properties, body):
        try:
            process_task(body)
            ch.basic_ack(delivery_tag=method.delivery_tag)
        except Exception as exc:
            print(f"Error processing message: {exc}", file=sys.stderr)
            ch.basic_nack(delivery_tag=method.delivery_tag, requeue=True)

    channel.basic_consume(queue=queue_name, on_message_callback=callback, auto_ack=False)
    print(f"Waiting for tasks on queue '{queue_name}'. Press CTRL+C to exit.")
    try:
        channel.start_consuming()
    except KeyboardInterrupt:
        print("Stopping consumer...")
        channel.stop_consuming()
    finally:
        connection.close()


def main():
    parser = argparse.ArgumentParser(description="RabbitMQ publisher/consumer for distributed task processing")
    subparsers = parser.add_subparsers(dest="command", required=True)

