    pub_parser.add_argument("--queue", default=QUEUE_NAME, help="Queue name")

    con_parser = subparsers.add_parser("consume", help="Start consuming task messages")
    con_parser.add_argument("--queue", default=QUEUE_NAME, help="Queue name")
    con_parser.add_argument("--prefetch", type=int, default=1, help="Prefetch count")

    args = parser.parse_args()

    if args.command == "publish":
        publish_task(args.message, args.queue)
    elif args.command == "consume":
        start_consumer(args.queue, args.prefetch)


